// transport currently inferred from a process-global boolean set deep in the send path:
extern thread_local bool g_isThroughUb;  // true => UB, false => SHM; no way to express TCP

Status Buffer::Publish(...) {
  auto rc = SendBufferViaUb(...);   // sets g_isThroughUb = true internally
  if (rc != Status::OK()) {
    // falls back to TCP, but nothing records the TCP transport here
    return PublishViaTcp(...);
  }
  return Status::OK();
}

