enum class AccessTransport { kShm, kUb, kTcp };
class AccessTransportTracker {
 public:
  static void Reset();
  static void Record(AccessTransport t);
  static AccessTransport Get();
};

namespace {
thread_local AccessTransport g_transport = AccessTransport::kShm;
}
void AccessTransportTracker::Reset() { g_transport = AccessTransport::kShm; }
void AccessTransportTracker::Record(AccessTransport t) { g_transport = t; }
AccessTransport AccessTransportTracker::Get() { return g_transport; }

