using namespace datasystem;
TEST(AccessTransportTracker, ResetIsShm) { AccessTransportTracker::Reset(); EXPECT_EQ(AccessTransportTracker::Get(), AccessTransport::kShm); }
TEST(AccessTransportTracker, RecordUb) { AccessTransportTracker::Record(AccessTransport::kUb); EXPECT_EQ(AccessTransportTracker::Get(), AccessTransport::kUb); }
TEST(AccessTransportTracker, RecordTcp) { AccessTransportTracker::Record(AccessTransport::kTcp); EXPECT_EQ(AccessTransportTracker::Get(), AccessTransport::kTcp); }
TEST(AccessTransportTracker, ThreadLocalIsolation) { AccessTransportTracker::Record(AccessTransport::kUb); std::thread([]{ EXPECT_EQ(AccessTransportTracker::Get(), AccessTransport::kShm); }).join(); }

